-- ייבוא 20 לידי בדיקה לטנאנט "הסוכנות שלי"
-- כל הלידים מסומנים source='DEMO_TEST' למחיקה קלה אחרי הבדיקה
-- להריץ ב: https://supabase.com/dashboard/project/scyfywvzoogfrlalgftv/sql/new

DO $$
DECLARE
  v_tenant uuid := '2a2143b9-20f4-4de7-8e54-8077f83f0f04';
  v_stage  uuid;
BEGIN
  -- Stage ראשון של הטנאנט (ליד חדש)
  SELECT id INTO v_stage FROM pipeline_stages
  WHERE tenant_id = v_tenant ORDER BY order_idx LIMIT 1;


  RAISE NOTICE '✅ הוכנסו 20 לידי בדיקה עם source=DEMO_TEST';
END $$;

